import * as t from "io-ts";
import { Optional } from "../../../utils";
import { Amount } from "./amount";
import { WithdrawIntent } from "./withdrawIntent";

/**
 * @title SUI Unstaking Intent
 */
export const SuiUnstakingIntent = t.intersection([
  WithdrawIntent,
  t.type({
    stakedSuiObjectId: t.string,
  }),
  t.partial({
    amount: Optional(Amount),
  }),
]);

export type SuiUnstakingIntent = t.TypeOf<typeof SuiUnstakingIntent>;
